- "Jama", "Pay kiya", "Received" -> Action: add_entry (with negative/payment flag if applicable, but usually mapped to ledger types).
- "Kitna hua", "Total batao" -> Action: get_summary

ALWAYS include a 'user_message' in a friendly WhatsApp tone.
`;

const PLATFORM_EXPERT_INSTRUCTION = `
You are the DukaanMitra Senior Architect. You help founders build the system.
Knowledge areas: Make.com scenarios, Google Sheets scaling, Gemini 2.5/3 API, WhatsApp Business API (Gupshup).
Be concise, technical, and strategic.
`;

const RESPONSE_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    action: { type: Type.STRING, enum: ["add_entry", "modify_entry", "get_summary", "add_bulk_entries", "clarification_required"] },
    customer_name: { type: Type.STRING },
    item: { type: Type.STRING },
    items: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          item: { type: Type.STRING },
          amount: { type: Type.NUMBER }
        }
      }
    },
    quantity: { type: Type.NUMBER },
    unit: { type: Type.STRING },
    amount: { type: Type.NUMBER },
    date: { type: Type.STRING },
    confidence: { type: Type.STRING, enum: ["high", "medium", "low"] },
    user_message: { type: Type.STRING },
    next_suggested_actions: { type: Type.ARRAY, items: { type: Type.STRING } }
  },
  required: ["action", "confidence", "user_message"]
};

export const parseMessage = async (text: string): Promise<ParsedBill> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: text,
      config: {
        systemInstruction: DUKAAN_AI_INSTRUCTION,
        temperature: 0.1,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini Parsing Error:", error);
    return {
      action: 'clarification_required',
      user_message: "Error processing request.",
      confidence: 'low'
    };
  }
};

export const parseImageBill = async (base64Image: string): Promise<ParsedBill> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: base64Image } },
          { text: "Extract all items and total amount from this bill. Return in bulk_entries format." }
        ]
      },
      config: {
        systemInstruction: DUKAAN_AI_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini Vision Error:", error);
    return {
      action: 'clarification_required',
      user_message: "Vision processing failed.",
      confidence: 'low'
    };
  }
};

export const generateChatResponse = async (prompt: string, history: any[] = []): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [
        ...history.map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.text }] })),
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        systemInstruction: PLATFORM_EXPERT_INSTRUCTION,
        thinkingConfig: { thinkingBudget: 32768 }
      }
    });

    return response.text || "No response generated.";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Issue connecting to platform brain.";
  }
};

export const getSmartSuggestions = async (transactions: Transaction[]): Promise<string[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const recentData = transactions.slice(-10).map(t => `${t.customerName}: ₹${t.amount} (${t.items})`).join(', ');

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Based on these recent transactions: [${recentData}], suggest 4 extremely short WhatsApp quick-replies a shopkeeper might type next in Hinglish. Examples: 'Rahul 200 udhaar', 'Amit 100 jama'. Keep them brief and contextually relevant.`,
      config: {
        systemInstruction: "You are a retail prediction engine. Output ONLY a JSON array of strings. No extra text.",
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Suggestions Error:", error);
    return ["Rahul 200 udhaar", "Aaj ka total", "Priya 500 jama"];
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { parseMessage, parseImageBill, getSmartSuggestions } from '../services/geminiService';
import { Customer, Transaction, SystemLog } from '../types';

interface SimulatorProps {
  customers: Customer[];
  setCustomers: React.Dispatch<React.SetStateAction<Customer[]>>;
  transactions: Transaction[];
  setTransactions: React.Dispatch<React.SetStateAction<Transaction[]>>;
  logs: SystemLog[];
  setLogs: React.Dispatch<React.SetStateAction<SystemLog[]>>;
}

const Simulator: React.FC<SimulatorProps> = ({ 
  customers, setCustomers, 
  transactions, setTransactions, 
  logs, setLogs 
}) => {
  const [message, setMessage] = useState("");
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeRoute, setActiveRoute] = useState<string | null>(null);
  const [costSaved, setCostSaved] = useState(0);
  const [aiRequests, setAiRequests] = useState(0);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [chatHistory, setChatHistory] = useState<{ sender: 'user' | 'bot'; text: string; isImage?: boolean; imageData?: string; isDoc?: boolean }[]>([
    { sender: 'bot', text: "Namaste! DukaanMitra AI Online. 🧠\nTry 'Rahul 500 udhaar' or 'Aaj ka total'." }
  ]);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [chatHistory, isProcessing]);

  // Fetch AI suggestions when transactions change
  useEffect(() => {
    const fetchSuggestions = async () => {
      const hints = await getSmartSuggestions(transactions);
      setSuggestions(hints);
    };
    fetchSuggestions();
  }, [transactions]);

  const handleSendMessage = async (customMsg?: string) => {
    const userMsg = (customMsg || message).trim();
    if (!userMsg || isProcessing) return;

    setMessage("");
    setChatHistory(prev => [...prev, { sender: 'user', text: userMsg }]);
    setIsProcessing(true);
    setActiveRoute(null);

    const mockUserPhone = "919876543210"; 
    const existingUser = customers.find(c => c.phone === mockUserPhone);
    const lowerMsg = userMsg.toLowerCase();

    // --- DAY 6: CHAI-SUTTA FILTER ---
    const garbageKeywords = ['ok', 'okay', 'thanks', 'thank you', 'theek', 'accha', '👍'];
    const isGarbage = garbageKeywords.some(kw => lowerMsg.includes(kw)) || userMsg.length <= 3;

    if (isGarbage) {
      setActiveRoute("CHAI_SUTTA_FILTER");
      setCostSaved(prev => prev + 1);
      await new Promise(res => setTimeout(res, 500));
      setChatHistory(prev => [...prev, { 
        sender: 'bot', 
        text: "Chai-Sutta Filter: Blocking garbage input. (Cost Saved! ☕)" 
      }]);
      setIsProcessing(false);
      return;
    }

    // --- BILLING ENGINE ---
    setActiveRoute("BILLING_LANE");
    setAiRequests(prev => prev + 1);
    const result = await parseMessage(userMsg);

    if (result.action === 'clarification_required' || result.confidence === 'low') {
      setActiveRoute("FALLBACK_HELP");
      setChatHistory(prev => [...prev, { 
        sender: 'bot', 
        text: result.user_message || "Maaf kijiye 🙏, samajh nahi aaya. Please clear likhein." 
      }]);
    } else if (result.action === 'get_summary') {
      setActiveRoute("INQUIRY_LANE");
      setChatHistory(prev => [...prev, { 
        sender: 'bot', 
        text: result.user_message || `Reporting summary...`
      }]);
    } else if (result.action === 'add_entry') {
      const newTrans: Transaction = {
        transId: `uuid-${Date.now()}`,
        storeId: existingUser?.storeId || "DM_DEL_001",
        phone: mockUserPhone,
        customerName: result.customer_name || "New Customer",
        amount: result.amount || 0,
        items: result.item || "General Purchase",
        date: new Date().toISOString(),
        intent: 'NEW_BILL'
      };

      setTransactions(prev => [...prev, newTrans]);
      if (existingUser) {
        setCustomers(prev => prev.map(c => 
          c.phone === mockUserPhone ? { ...c, totalLTV: c.totalLTV + (newTrans.amount || 0) } : c
        ));
      }

      setChatHistory(prev => [...prev, { 
        sender: 'bot', 
        text: result.user_message || `✅ Entry Confirm!\n${newTrans.customerName}: ₹${newTrans.amount}` 
      }]);
    }

    setIsProcessing(false);
  };

  const handleImageUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        const cleanBase64 = base64.split(',')[1];
        simulateImageBill(cleanBase64, base64);
      };
      reader.readAsDataURL(file);
    }
  };

  const simulateImageBill = async (base64Data: string, fullDataUrl: string) => {
    setIsProcessing(true);
    setChatHistory(prev => [...prev, { sender: 'user', text: "Analyzing bill...", isImage: true, imageData: fullDataUrl }]);

    setAiRequests(prev => prev + 1);
    setActiveRoute("VISION_ENGINE");

    try {
      const result = await parseImageBill(base64Data);

      if (result.items && result.action === 'add_bulk_entries') {
        const newBulkTrans = result.items.map((item, idx) => ({
          transId: `uuid-vision-${Date.now()}-${idx}`,
          storeId: "DM_DEL_001",
          phone: "919876543210",
          customerName: result.customer_name || "Vision Customer",
          amount: item.amount,
          items: item.item,
          date: new Date().toISOString(),
          intent: 'NEW_BILL' as const
        }));

        setTransactions(prev => [...prev, ...newBulkTrans]);
      }

      setChatHistory(prev => [...prev, { sender: 'bot', text: result.user_message }]);
    } catch (err) {
      setChatHistory(prev => [...prev, { sender: 'bot', text: "Maaf kijiye, vision processing fail ho gaya." }]);
    } finally {
      setIsProcessing(false);
      setActiveRoute(null);
    }
  };

  return (
    <div className="flex flex-col lg:flex-row gap-6 h-full min-h-[500px]">
      {/* Native App View Container */}
      <div className="lg:flex-1 max-w-md mx-auto w-full bg-slate-100 rounded-[2.5rem] shadow-2xl border-8 border-slate-900 overflow-hidden flex flex-col relative aspect-[9/18]">
        {/* Device Status Bar */}
        <div className="h-6 bg-slate-900 flex justify-between px-6 items-center text-[10px] text-white/50 font-bold uppercase">
          <span>9:41</span>
          <div className="flex space-x-1">
            <span>📶</span>
            <span>🔋</span>
          </div>
        </div>

        {/* App Header */}
        <div className="bg-indigo-600 p-4 pt-6 text-white flex items-center justify-between shrink-0">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 bg-indigo-500 rounded-full flex items-center justify-center font-bold shadow-lg">DM</div>
            <div>
              <p className="font-bold text-sm">DukaanMitra AI</p>
              <div className="flex items-center space-x-1">
                <span className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-pulse"></span>
                <p className="text-[10px] opacity-80">Online</p>
              </div>
            </div>
          </div>
          <div className="text-right">
            <p className="text-[8px] font-black opacity-60 uppercase">Day 6 Saver</p>
            <p className="text-sm font-black text-emerald-300">₹{costSaved * 2}</p>
          </div>
        </div>

        {/* Chat Feed */}
        <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-[#e5ddd5] no-scrollbar">
          {chatHistory.map((chat, i) => (
            <div key={i} className={`flex ${chat.sender === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
              <div className={`max-w-[85%] p-3 rounded-2xl text-sm shadow-sm relative ${
                chat.sender === 'user' 
                  ? 'bg-[#dcf8c6] text-slate-800 rounded-tr-none' 
                  : 'bg-white text-slate-800 rounded-tl-none border-l-4 border-l-indigo-500'
              }`}>
                {chat.isImage && (
                  <div className="w-full mb-2 overflow-hidden rounded-lg border border-slate-200">
                    <img src={chat.imageData} alt="Bill" className="w-full h-auto object-cover max-h-48" />
                  </div>
                )}
                <p className="whitespace-pre-wrap leading-relaxed">{chat.text}</p>
                <span className="text-[8px] text-slate-400 absolute bottom-1 right-2 uppercase font-bold">Just Now</span>
              </div>
            </div>
          ))}
          {isProcessing && (
            <div className="flex justify-start">
              <div className="bg-white/80 backdrop-blur-sm p-3 rounded-2xl flex items-center space-x-2 shadow-sm">
                <div className="flex space-x-1">
                  <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce"></div>
                  <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                  <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                </div>
                <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Processing...</span>
              </div>
            </div>
          )}
          <div ref={chatEndRef} />
        </div>

        {/* Suggestions Bar */}
        <div className="bg-slate-50/80 backdrop-blur-md px-3 py-2 flex items-center space-x-2 overflow-x-auto no-scrollbar border-t border-slate-200">
           {suggestions.map((s, i) => (
             <button
               key={i}
               onClick={() => handleSendMessage(s)}
               className="whitespace-nowrap px-3 py-1.5 bg-white border border-slate-200 rounded-full text-[10px] font-bold text-slate-600 hover:bg-indigo-50 hover:border-indigo-200 hover:text-indigo-600 transition-all shadow-sm shrink-0"
             >
               {s}
             </button>
           ))}
           {suggestions.length === 0 && <span className="text-[9px] text-slate-400 uppercase font-black px-2">Predicting...</span>}
        </div>

        {/* Chat Input */}
        <div className="p-3 bg-white border-t flex items-center space-x-2 shrink-0 safe-bottom">
          <input 
            type="file" 
            accept="image/*" 
            ref={fileInputRef} 
            onChange={handleImageUpload} 
            className="hidden" 
          />
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="w-10 h-10 rounded-full flex items-center justify-center text-xl text-slate-400 hover:bg-slate-100 transition"
          >
            📷
          </button>
          <div className="flex-1 relative">
            <input 
              type="text" 
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder="e.g. Rahul 500 cheeni"
              className="w-full bg-slate-100 rounded-full px-5 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all border-none"
            />
          </div>
          <button 
            onClick={() => handleSendMessage()} 
            disabled={isProcessing || !message.trim()} 
            className="bg-indigo-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-lg hover:bg-indigo-700 active:scale-95 transition-all disabled:opacity-30"
          >
            ➔
          </button>
        </div>
      </div>

      {/* Control Panel (Desktop Only) */}
      <div className="hidden lg:flex lg:flex-col lg:w-96 space-y-6">
        <div className="bg-white p-6 rounded-3xl shadow-xl border border-slate-100">
           <h3 className="text-xl font-bold mb-4 flex items-center space-x-2 italic">
              <span className="text-indigo-600">🧠</span>
              <span>AI Core Monitoring</span>
           </h3>
           <div className="space-y-3">
              <div className={`p-4 rounded-2xl border transition-all ${activeRoute === 'CHAI_SUTTA_FILTER' ? 'bg-amber-100 border-amber-300 scale-105' : 'bg-slate-50 border-slate-100 opacity-60'}`}>
                 <p className="text-xs font-black uppercase text-amber-700">Pre-Filter</p>
                 <p className="text-[10px] text-amber-600">Garbage input cleanup active.</p>
              </div>
              <div className={`p-4 rounded-2xl border transition-all ${activeRoute === 'BILLING_LANE' || activeRoute === 'VISION_ENGINE' ? 'bg-indigo-100 border-indigo-300 scale-105' : 'bg-slate-50 border-slate-100 opacity-60'}`}>
                 <p className="text-xs font-black uppercase text-indigo-700">Intent Engine</p>
                 <p className="text-[10px] text-indigo-600">Gemini-3-Flash parsing JSON.</p>
              </div>
              <div className={`p-4 rounded-2xl border transition-all ${activeRoute === 'FALLBACK_HELP' ? 'bg-rose-100 border-rose-300 scale-105' : 'bg-slate-50 border-slate-100 opacity-60'}`}>
