                 <p className="text-[10px] text-rose-600">Triggered on low probability.</p>
              </div>
           </div>
        </div>

        <div className="bg-slate-900 text-white p-6 rounded-3xl shadow-xl">
           <h3 className="text-xs font-bold uppercase tracking-widest text-indigo-400 mb-4">Economics Ledger</h3>
